-- NULL ordering, DISTINCT, LIMIT/OFFSET, ordinals.
CREATE TABLE n4 (v int, w text);
INSERT INTO n4 VALUES (3,'c'),(NULL,'n'),(1,'a'),(2,'b'),(1,'a');
SELECT v FROM n4 ORDER BY v;
SELECT v FROM n4 ORDER BY v DESC;
SELECT v, w FROM n4 ORDER BY 1, 2;
SELECT DISTINCT v FROM n4 ORDER BY v;
SELECT DISTINCT v, w FROM n4 ORDER BY v, w;
SELECT v FROM n4 ORDER BY v LIMIT 2;
SELECT v FROM n4 ORDER BY v LIMIT 2 OFFSET 2;
SELECT v FROM n4 ORDER BY v OFFSET 4;
DROP TABLE n4;
